operation.expression:
let $x := $temp.tmp_purposeId 
return string-join(
  for $p in $x/purposes/purpose
  where $p/attributes/consentType = "COMMON_CONSENT"
        and $p/attributes/countryCode = $input.countryCode 
        and $p/attributes/nmscCode = $input.nmscCode 
  return $p/purposeId,
  ","
)

let $x := $temp.tmp_purposeId 
return string-join(
  for $p in $x/purposes/purpose
  where $p/attributes/consentType = "COMMUNICATION_CHANNELS"
        and $p/attributes/countryCode = $input.countryCode 
        and $p/attributes/nmscCode = $input.nmscCode 
        and $p/attributes/brand = $input.brand 
  return $p/purposeId,
  ","
)

let $x := $temp.tmp_purposeId 
return string-join(
  for $p in $x/purposes/purpose
  where $p/attributes/consentType = "MARKETING_CONSENT"
        and $p/attributes/countryCode = $input.countryCode 
        and $p/attributes/nmscCode = $input.nmscCode 
        and $p/attributes/brand = $input.brand 
  return $p/purposeId,
  ","
)

util:iif(util:toJSON($output.brandConsents) = '{}',fn:concat('"consents": {
    "marketingConsents": {
      "brand": "', $input.brand ,'",
      "purposes": []
    }'),let $brand := $input.brand
let $brandconsent := $output.brandConsents
let $communicationchannels := $output.CommunicationChannels
let $lastinteractiondate := $output.LastInteractionDate
return
fn:concat(
'"consents": {"marketingConsents": {',
'"brand":"',$input.brand,'",',
'"purposes": [',
fn:string-join(
for $b_consent in $brandconsent 
return fn:concat(
'{',
'"purposeCode": "',data($b_consent/purposeCode),'",',
'"status": "', data($b_consent/status),'",',
'"lastInteractionDate": "', data($b_consent/lastInteractionDate),'"',
'}'
),
','
),
'],',
'"communicationChannels": {',
'"lastInteractionDate": ',$lastinteractiondate,',',
'"channels": [',
fn:string-join(
for $channel in ($communicationchannels)
return 
$channel,
','
),
']',
'}',
'}'
))

  util:iif(util:toJSON($output.commonConsents) = '{}',    '"commonConsents": {
      "purposes": []
    }
  }',let $common_output := $output.commonConsents 
return
fn:concat(
  '"commonConsents": {',
  '"purposes": [',
  string-join(
    for $item in $common_output
    return fn:concat(
      '{',
      '"purposeCode": "', data($item/purposeCode), '",',
      '"status": "', data($item/status),'",',
      '"lastInteractionDate": "', data($item/lastInteractionDate), '"',
      '}'
    ),
    ','
  ),
  ']',
  '}}'
))
